#include <bits/stdc++.h>
using namespace std;
const int N=150004;
struct Building{
	int t,e;
}a[N];
bool cmp(Building x,Building y){
	if(x.e==y.e)
		return x.t<y.t;
	return x.e<y.e;
}
int n;
long long sum;
priority_queue<int> q;
int main(){
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
		scanf("%d%d",&a[i].t,&a[i].e);
	sort(a+1,a+n+1,cmp);
	for(int i=1;i<=n;i++){
		q.push(a[i].t),sum+=a[i].t;
		if(a[i].e<sum)
			sum-=q.top(),q.pop();
	}
	printf("%d",(int)q.size());
	return 0;
}
